async function main() {
  const key = 'vck_4dwPtM19h5uqaMcWuFhLylu87P6jo7oFD3nXLLkbjOG0rVcI2T3JyBUI';
  const url = 'https://ai-gateway.vercel.sh/v1/chat/completions';

  console.log('Testing new Vercel AI Gateway key...');
  console.log(`Key prefix: ${key.slice(0, 8)}...`);
  console.log(`Key length: ${key.length}`);

  const resp = await fetch(url, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${key}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      model: 'openai/gpt-4o',
      messages: [{ role: 'user', content: 'Say OK' }],
      max_tokens: 10,
    }),
  });

  console.log(`\nHTTP Status: ${resp.status}`);
  const text = await resp.text();

  if (resp.status === 200) {
    const data = JSON.parse(text);
    const answer = data.choices?.[0]?.message?.content;
    console.log(`✓ KEY VALID — Response: "${answer}"`);
    console.log(`  Model: ${data.model}`);
    console.log(`  Usage: prompt=${data.usage?.prompt_tokens} completion=${data.usage?.completion_tokens}`);
  } else {
    console.log(`✗ KEY INVALID — Response:`);
    console.log(text.slice(0, 500));
  }
}
main().catch(e => { console.error('FATAL:', e.message); process.exit(1); });
